import os
from flask import Flask, jsonify
from datetime import datetime, timedelta
import pickle
import json
import hashlib

app = Flask(__name__)

# Cache configuration
CACHE_DIR = 'cache'
EXPIRATION_TIME = 60 * 60  # 1 hour in seconds

def cache_response(response):
    """Cache API response to disk"""
    cache_key = hashlib.sha256(json.dumps(response, sort_keys=True).encode()).hexdigest()
    cache_file_path = os.path.join(CACHE_DIR, f'{cache_key}.json')
    
    with open(cache_file_path, 'w') as file:
        json.dump(response, file)
        
def load_cached_response(cache_key):
    """Load cached API response from disk"""
    cache_file_path = os.path.join(CACHE_DIR, f'{cache_key}.json')
    
    try:
        with open(cache_file_path, 'r') as file:
            return json.load(file)
    except FileNotFoundError:
        return None

def is_cache_expired(cache_key):
    """Check if cached API response has expired"""
    cache_file_path = os.path.join(CACHE_DIR, f'{cache_key}.json')
    
    try:
        with open(cache_file_path, 'r') as file:
            timestamp = json.load(file)['timestamp']
            
            return datetime.now() > datetime.fromtimestamp(timestamp + EXPIRATION_TIME)
    except FileNotFoundError:
        return False

@app.route('/api/<path:path>', methods=['GET'])
def api_response(path):
    cache_key = hashlib.sha256(json.dumps({'path': path}, sort_keys=True).encode()).hexdigest()
    
    cached_response = load_cached_response(cache_key)
    
    if cached_response and not is_cache_expired(cache_key):
        return jsonify(cached_response)
        
    # Simulate expensive API call
    response = {'data': f'API Response for {path}', 'timestamp': datetime.now().timestamp()}
    
    cache_response(response)
    
    return jsonify(response)

if __name__ == '__main__':
    app.run(debug=True)